# Extract prices from the input items
gold = _items[0]["json"].get("goldPrice")
silver = _items[1]["json"].get("silverPrice")

# Calculate the ratio
if gold and silver:
    ratio = round(gold / silver, 2)
else:
    ratio = 0

# Return the data in n8n's required format
return [
    {
        "json": {
            "goldPrice": gold,
            "silverPrice": silver,
            "ratio": ratio
        }
    }
]

