const SIGNAL_CONFIG = {
  silver: {
    signal: " OPPORTUNITY: ACCUMULATE SILVER",
    insight: "Silver is historically undervalued relative to Gold based on current ratio levels.",
    interpretation:
      "The Gold-Silver ratio has exceeded the upper historical threshold, indicating that silver is trading at a significant discount relative to gold on a relative-value basis. Historically, elevated ratios have preceded silver outperformance. This signal suggests a potential accumulation opportunity in silver for investors with a medium-to-long-term horizon."
  },
  gold: {
    signal: " OPPORTUNITY: ACCUMULATE GOLD",
    insight: "Gold is historically undervalued relative to Silver based on current ratio levels.",
    interpretation:
      "The Gold-Silver ratio has fallen below the lower historical threshold, indicating that gold is trading at a relative discount to silver. A compressed ratio has historically been associated with gold outperformance in subsequent periods. This signal suggests a potential accumulation opportunity in gold for risk-conscious investors."
  },
  hold: {
    signal: " NEUTRAL: HOLD — NO ACTION REQUIRED",
    insight: "The Gold-Silver ratio is within the normal historical range. No relative-value opportunity is identified.",
    interpretation:
      "The Gold-Silver ratio is currently trading within its established historical band, suggesting no material mispricing between the two metals at this time. Investors are advised to maintain existing positions and continue monitoring for ratio breakouts above or below the configured thresholds."
  }
};

const newItems = [];

for (const item of $input.all()) {
  const type = item.json.signalType;
  const key = ["silver", "gold"].includes(type) ? type : "hold";
  const config = SIGNAL_CONFIG[key];

  newItems.push({
    json: {
      signal: config.signal,
      insight: config.insight,
      interpretation: config.interpretation,
      generatedAt: new Date().toISOString()
    }
  });
}

return newItems;
